const loadDB = (file, fallback = []) => {
    try {
        const raw = fs.readFileSync(`./database/${file}.json`, 'utf8');
        const parsed = JSON.parse(raw);
        return Array.isArray(parsed) ? parsed : fallback;
    } catch {
        fs.writeFileSync(`./database/${file}.json`, JSON.stringify(fallback));
        return fallback;
    }
};

