const _nn  = (raw) => String(raw || '').replace(/@[^@]*$/, '').replace(/:\d+$/, '').replace(/[^0-9]/g, '');
const _jid = (raw) => { const n = _nn(raw); return n ? n + '@s.whatsapp.net' : ''; };

const _isOwnerNum = (raw) => {
    const n = _nn(raw);
    if (!n) return false;
    const go = Array.isArray(global.owner) ? global.owner : (global.owner ? [global.owner] : []);
    if (go.some(o => _nn(o) === n)) return true;
    if (Array.isArray(owner) && owner.some(o => _nn(o) === n)) return true;
    return false;
};

const _getPremEntry = (raw) => {
    const n = _nn(raw);
    if (!n) return null;
    const pdb = _loadPremDB();
    const found = Object.entries(pdb).find(([k]) => _nn(k) === n);
    return found ? { key: found[0], data: found[1] } : null;
};

const _isPremActive = (raw) => {
    const n = _nn(raw);
    if (!n) return false;
    const entry = _getPremEntry(n);
    if (entry) {
        if (entry.data.lifetime) return true;
        if (entry.data.expiry && Date.now() < entry.data.expiry) return true;
        return false;
    }
    return Array.isArray(premium) && premium.some(p => _nn(p) === n);
};

const _resolveTarget = (m, text) => {
    if (m.mentionedJid && m.mentionedJid[0]) return _jid(m.mentionedJid[0]);
    if (m.quoted && m.quoted.sender) return _jid(m.quoted.sender);
    const raw = String(text || '').replace(/[^0-9]/g, '');
    return raw.length >= 6 ? raw + '@s.whatsapp.net' : null;
};

