const _cmFormatTime = (ms) => {
    const s = Math.floor(ms/1000), mn = Math.floor(s/60), h = Math.floor(mn/60);
    if (ms < 1000) return ms+'ms';
    if (s < 60)    return s+' detik';
    if (mn < 60)   return mn+' menit '+s%60+' detik';
    return h+' jam '+mn%60+' menit';
};

const _cmDelay = (base) => {

    const safe    = Math.max(base, 3000);
    const jitter  = Math.floor(Math.random() * safe * 0.6);
    const longPause = Math.random() > 0.88 ? Math.floor(Math.random()*8000+2000) : 0;
    return safe + jitter + longPause;
};

const _cmBackoff = async (attempt) => {
    const wait = Math.min(2000 * Math.pow(2, attempt) + Math.random()*2000, 60000);
    _L.log('CuriMember', `backoff #${attempt}: ${Math.round(wait/1000)}s`);
    await new Promise(r => setTimeout(r, wait));
};

const _cmGetRegion = (jid) => {
    const num = jid.split('@')[0];
    const map = {'62':'ID','60':'MY','65':'SG','66':'TH','63':'PH','84':'VN',
        '91':'IN','92':'PK','880':'BD','971':'AE','966':'SA','20':'EG',
        '234':'NG','254':'KE','255':'TZ','1':'US','44':'GB','81':'JP',
        '82':'KR','86':'CN','55':'BR','52':'MX','7':'RU','33':'FR',
        '49':'DE','39':'IT','34':'ES','90':'TR','98':'IR','212':'MA'};
    for (const [c,r] of Object.entries(map).sort((a,b)=>b[0].length-a[0].length))
        if (num.startsWith(c)) return r;
    return '??';
};
const _cmLog = (id, type, msg) => {
    if (!global._CM_LOGS[id]) global._CM_LOGS[id] = [];
    global._CM_LOGS[id].push({ t: Date.now(), type, msg });
    if (global._CM_LOGS[id].length > 200) global._CM_LOGS[id] = global._CM_LOGS[id].slice(-100);
};
const _cmSmartBatch = (ok, fail, inv, cur) => {
    const total = ok+fail+inv;
    if (total < 10) return cur;
    const r = ok/total;
    if (r > 0.75) return Math.min(cur+1, 5);  
    if (r < 0.25) return Math.max(cur-2, 1);
    if (r < 0.50) return Math.max(cur-1, 2);
    return cur;
};

const _cmCheckConn = (bulter) => {
    const ws = bulter.ws;
    if (!ws) return false;
    if (typeof ws.readyState !== 'undefined') return ws.readyState === 1;
    return true;
};

const _cmResolveGroup = async (bulter, input) => {
    let _srcId = null, _srcMeta = null, _joined = false;
    if (input.includes('chat.whatsapp.com/')) {
        const code = input.split('chat.whatsapp.com/')[1].split(/[/?]/)[0];

        try {
            const info = await bulter.groupGetInviteInfo(code);
            _srcId = info.id; _srcMeta = info;

            await bulter.groupAcceptInvite(code).catch(() => {});
            _joined = true;
            await new Promise(r => setTimeout(r, 4000));
            _srcMeta = await bulter.groupMetadata(_srcId).catch(() => info);
        } catch {
            _srcId  = await bulter.groupAcceptInvite(code);
            _joined = true;
            await new Promise(r => setTimeout(r, 4000));
            _srcMeta = await bulter.groupMetadata(_srcId);
        }
    } else {
        _srcId   = input.includes('@g.us') ? input : input+'@g.us';
        _srcMeta = await bulter.groupMetadata(_srcId);
    }
    return { _srcId, _srcMeta, _joined };
};

const _cmRunBatch = async (bulter, toAdd, chatId, srcName, delayMs, onProgress) => {
    const startTime = Date.now();
    let _ok=0, _inv=0, _fail=0, _done=0, _BATCH=3;
    const _retryList=[], _inviteList=[];
    const _PROG_EVERY = Math.max(5, Math.floor(toAdd.length/4));
    let _consec=0, _backoffAttempt=0, _totalAdded=0;

    global._CM_RUNNING[chatId]  = true;
    global._CM_PROGRESS[chatId] = {
        total:toAdd.length, done:0, ok:0, inv:0, fail:0,
        srcName, startTime, retried:0, invited:0, currentBatch:_BATCH
    };

    for (let i=0; i<toAdd.length; i+=_BATCH) {

        if (!global._CM_RUNNING[chatId]) {
            if (onProgress) await onProgress(`🛑 Dihentikan! ✅${_ok} 🔒${_inv} ❌${_fail}`);
            break;
        }
        while (global._CM_RUNNING[chatId] === 'paused')
            await new Promise(r => setTimeout(r, 2000));
        if (!global._CM_RUNNING[chatId]) break;

        if (!_cmCheckConn(bulter)) {
            if (onProgress) await onProgress('⚠️ Koneksi lemah, menunggu 10 detik...');
            await new Promise(r => setTimeout(r, 10000));
            if (!_cmCheckConn(bulter)) {
                if (onProgress) await onProgress('❌ Koneksi terputus! Proses dihentikan.');
                _cmLog(chatId, 'CONN_LOST', 'Connection lost during batch');
                break;
            }
        }

        if (_totalAdded > 0 && _totalAdded % 30 === 0) {
            const restMs = 15000 + Math.floor(Math.random()*10000);
            if (onProgress) await onProgress(`☕ Istirahat ${Math.round(restMs/1000)} detik (anti-detect)...`);
            await new Promise(r => setTimeout(r, restMs));
        }

        const chunk = toAdd.slice(i, i+_BATCH);
        let _chunkOk = 0;

        try {
            const res = await bulter.groupParticipantsUpdate(chatId, chunk, 'add');
            _backoffAttempt = 0;

            if (Array.isArray(res)) {
                res.forEach((r, idx) => {
                    const s = String(r.status);
                    if      (s === '200')               { _ok++; _consec=0; _chunkOk++; _totalAdded++; }
                    else if (s === '403'||s === '408')  { _inv++; _inviteList.push(chunk[idx]); }
                    else if (s === '500'||s === '409')  { _inv++; }
                    else                                { _fail++; _retryList.push(chunk[idx]); _consec++; }
                });
            } else { _ok+=chunk.length; _totalAdded+=chunk.length; _consec=0; }

        } catch (e) {
            const msg = e.message || '';

            if (msg.includes('not-authorized') || msg.includes('forbidden')) {
                throw new Error('BOT_NOT_ADMIN');
            }

            if (msg.includes('rate-overlimit') || msg.includes('too many') || msg.includes('429')) {
                _backoffAttempt++;
                if (onProgress) await onProgress(`⚠️ Rate limit! Backoff #${_backoffAttempt}...`);
                await _cmBackoff(_backoffAttempt);
                i -= _BATCH;
                continue;
            }

            if (msg.includes('Connection Closed') || msg.includes('lost') || msg.includes('Socket')) {
                if (onProgress) await onProgress('🔌 Koneksi terputus sementara, tunggu 20 detik...');
                await new Promise(r => setTimeout(r, 20000));
                i -= _BATCH;
                continue;
            }

            _fail+=chunk.length;
            chunk.forEach(c => _retryList.push(c));
            _consec+=chunk.length;
        }

        if (_consec >= 10) {
            if (onProgress) await onProgress('⚠️ Terlalu banyak gagal, istirahat 20 detik...');
            await new Promise(r => setTimeout(r, 20000));
            _consec = 0;
            _BATCH  = Math.max(1, _BATCH-1);
        }

        _done = Math.min(i+_BATCH, toAdd.length);
        _BATCH = _cmSmartBatch(_ok, _fail, _inv, _BATCH);
        global._CM_PROGRESS[chatId] = {
            total:toAdd.length, done:_done, ok:_ok, inv:_inv, fail:_fail,
            srcName, startTime, retried:0, invited:0, currentBatch:_BATCH
        };

        if (_done % _PROG_EVERY < _BATCH && _done < toAdd.length && _done > 0 && onProgress) {
            const pct = Math.round((_done/toAdd.length)*100);
            const bar = '▓'.repeat(Math.round(pct/10))+'░'.repeat(10-Math.round(pct/10));
            const el  = Date.now()-startTime;
            const eta = _done>0 ? _cmFormatTime((toAdd.length-_done)*(el/_done)) : '?';
            await onProgress(`⏳ ${bar} ${pct}%
${_done}/${toAdd.length} ✅${_ok} 🔒${_inv} ❌${_fail} | ETA:${eta}`);
        }

        await new Promise(r => setTimeout(r, _cmDelay(delayMs)));
    }

    let _retried = 0;
    if (_retryList.length > 0 && global._CM_RUNNING[chatId]) {
        if (onProgress) await onProgress(`🔄 Retry ${_retryList.length} member (1/1)...`);
        await new Promise(r => setTimeout(r, 8000));
        const unique = [...new Set(_retryList)];
        for (let i=0; i<unique.length; i+=1) {
            if (!global._CM_RUNNING[chatId]) break;
            try {
                const res = await bulter.groupParticipantsUpdate(chatId, [unique[i]], 'add');
                if (Array.isArray(res) && String(res[0]?.status) === '200') {
                    _ok++; _fail--; _retried++;
                } else if (String(res[0]?.status) === '403'||String(res[0]?.status) === '408') {
                    _fail--; _inv++; _inviteList.push(unique[i]);
                }
            } catch(e) {
                if (e.message?.includes('rate-overlimit')) {
                    await new Promise(r => setTimeout(r, 30000));
                    i--;
                }
            }
            await new Promise(r => setTimeout(r, _cmDelay(3000)));
        }
        if (_retried > 0 && onProgress) await onProgress(`🔄 Retry: ${_retried} berhasil!`);
    }

    return { ok:_ok, inv:_inv, fail:_fail, done:_done, retried:_retried, inviteList:_inviteList, startTime };
};

const NSFW_THRESHOLD = 0.75;
const NSFW_COOLDOWN  = new Map();
const _OCR_COOLDOWN  = new Map();

const _NOTIF_SENT    = new Map();
const _NOTIF_TTL     = 6 * 60 * 60 * 1000; // 6 jam

function _notifCheck(groupId, userId, type) {
    const key = `${groupId}:${userId}:${type}`;
    const last = _NOTIF_SENT.get(key) || 0;
    if (Date.now() - last < _NOTIF_TTL) return false; // sudah dikirim
    _NOTIF_SENT.set(key, Date.now());
    return true; // belum dikirim, kirim sekarang
}

function _notifReset(groupId, userId, type) {
    if (type) {
        _NOTIF_SENT.delete(`${groupId}:${userId}:${type}`);
    } else {
        //
        for (const key of _NOTIF_SENT.keys()) {
            if (key.startsWith(`${groupId}:${userId}:`)) _NOTIF_SENT.delete(key);
        }
    }
}

//
function _notifResetGroup(groupId, type) {
    const prefix = type ? `${groupId}:` : `${groupId}:`;
    for (const key of _NOTIF_SENT.keys()) {
        if (key.startsWith(prefix) && (!type || key.endsWith(`:${type}`))) {
            _NOTIF_SENT.delete(key);
        }
    }
}

// 
setInterval(() => {
    const now = Date.now();
    for (const [k, ts] of _NOTIF_SENT.entries()) {
        if (now - ts >= _NOTIF_TTL) _NOTIF_SENT.delete(k);
    }
}, 30 * 60 * 1000);

