async function groqListModels() {
    var apiKey = getNextGroqKey()
    try {
        var res = await axios.get('https://api.groq.com/openai/v1/models', {
            headers: { 'Authorization': 'Bearer ' + apiKey, 'Accept': 'application/json' },
            timeout: 15000
        })
        if (res.data && res.data.data) return res.data.data.map(function(m) { return { id: m.id, owned_by: m.owned_by } })
        return []
    } catch (e) { return [] }
}
