const getJadwalSholat = async (kota, negara = 'Indonesia', metode = 11) => {
    const now      = new Date();
    const tanggal  = `${String(now.getDate()).padStart(2,'0')}-${String(now.getMonth()+1).padStart(2,'0')}-${now.getFullYear()}`;
    const url      = `https://api.aladhan.com/v1/timingsByCity/${tanggal}?city=${encodeURIComponent(kota)}&country=${encodeURIComponent(negara)}&method=${metode}`;
    const res      = await axios.get(url, { timeout: 15000, headers: { 'User-Agent': 'Mozilla/5.0' } });
    if (res.data?.code !== 200 && res.data?.status !== 'OK') throw new Error('API error: ' + (res.data?.status || 'unknown'));
    return res.data.data;
};

const parseWaktu = (timeStr) => {
    try {
        const [h, m] = timeStr.split(':').map(Number);
        return { h, m, str: `${String(h).padStart(2,'0')}:${String(m).padStart(2,'0')}` };
    } catch { return { h: 0, m: 0, str: '00:00' }; }
};

const getHijriah = (data) => {
    try {
        const h = data?.date?.hijri;
        if (!h) return '';
        return `${h.day} ${h.month?.en} ${h.year} H`;
    } catch { return ''; }
};

if (!global._autoshalat) global._autoshalat = {};

const kirimAdzan = async (bulter, groupId, prayerKey, waktuStr, kota, participants) => {
    const info = PRAYER_INFO[prayerKey];
    if (!info) return;

    if (global._autoshalat[groupId]) return;

    let thumbBuf;
    try { thumbBuf = fs.readFileSync(ADZAN_ASSETS.thumbnail); }
    catch { thumbBuf = Buffer.alloc(0); }

    const mentions = (participants || []).map(p => p.id || p.jid).filter(Boolean);

    global._autoshalat[groupId] = [
        bulter.sendMessage(groupId, {
            audio: { url: ADZAN_ASSETS.audio_adzan },
            mimetype: 'audio/mp4',
            ptt: true,
            contextInfo: {
                externalAdReply: {
                    showAdAttribution: false,
                    mediaType: 1,
                    mediaUrl: '',
                    title: `Selamat menunaikan Ibadah Sholat ${info.name}`,
                    body: `${info.emoji} ${waktuStr} WIB  •  📍 ${kota}`,
                    sourceUrl: '',
                    thumbnail: thumbBuf,
                    renderLargerThumbnail: true
                }
            }
        }, { mentions }),
        setTimeout(() => {
            delete global._autoshalat[groupId];
        }, 57000)
    ];

    await new Promise(r => setTimeout(r, 3000));

    try {
        await bulter.sendMessage(groupId, {
            text:
                `${info.color} *WAKTU ${info.name.toUpperCase()}* ${info.color}\n\n` +
                `🕌 *${info.arabic}*  •  ${info.emoji} ${info.name}\n` +
                `🕐 *Waktu  :* ${waktuStr} WIB\n` +
                `📍 *Kota   :* ${kota}\n\n` +
                `_Allahu Akbar, Allahu Akbar..._\n` +
                `_Asyhadu an laa ilaaha illallah..._\n` +
                `_Asyhadu anna Muhammadan Rasulullah..._\n` +
                `_Hayya 'alash-shalah..._\n` +
                `_Hayya 'alal-falah..._` +
                `${prayerKey === 'Fajr' ? '\n_Ash-shalatu khairum minan-naum..._' : ''}\n` +
                `_Allahu Akbar, Allahu Akbar..._\n` +
                `_Laa ilaaha illallah..._\n\n` +
                `📿 *${info.doa}*\n\n` +
                `> 🕌 *${global.namaBot || 'BulterBot'}*  •  Pengingat Sholat Otomatis`,
            mentions
        });
    } catch {}
};

let _adzanScheduled = false;
const initAdzanScheduler = async (bulter) => {
    if (_adzanScheduled) return;
    _adzanScheduled = true;

    setInterval(async () => {
        try {
            const db = loadAdzan();
            const aktifGrups = Object.entries(db).filter(([, v]) => v.aktif);
            if (!aktifGrups.length) return;

            const datek   = new Date((new Date()).toLocaleString('en-US', { timeZone: 'Asia/Jakarta' }));
            const hours   = datek.getHours();
            const minutes = datek.getMinutes();
            const timeNow = `${String(hours).padStart(2,'0')}:${String(minutes).padStart(2,'0')}`;

            const kotaList = [...new Set(aktifGrups.map(([, v]) => v.kota || 'Jakarta'))];

            for (const kota of kotaList) {
                let jadwalData;
                try { jadwalData = await getJadwalSholat(kota); }
                catch { continue; }

                const timings  = jadwalData.timings;
                const grupsKota = aktifGrups.filter(([, v]) => (v.kota || 'Jakarta') === kota);

                for (const [prayerKey, info] of Object.entries(PRAYER_INFO)) {
                    const rawTime = timings[prayerKey];
                    if (!rawTime) continue;
                    const { str } = parseWaktu(rawTime);

                    if (timeNow !== str) continue;

                    _L.log('Adzan', `${info.name} — ${str} WIB — ${kota} — ${grupsKota.length} grup`);

                    for (const [groupId] of grupsKota) {
                        try {
                            let participants = [];
                            try {
                                const meta = await bulter.groupMetadata(groupId).catch(() => ({}));
                                participants = meta.participants || [];
                            } catch {}

                            await kirimAdzan(bulter, groupId, prayerKey, str, kota, participants);
                            await new Promise(r => setTimeout(r, 2500));
                        } catch (e) {
                            console.error(`[Adzan] Error kirim ke ${groupId}:`, e.message);
                        }
                    }
                }
            }
        } catch (e) {
            console.error('[Adzan Cron]', e.message);
        }
    }, 60000);

    _L.log('Adzan', 'Scheduler aktif — cek tiap menit (WIB)');
};

const isSewaActive = (groupId) => {
    const db  = loadSewa();
    const row = db[groupId];
    if (!row) return false;
    if (row.lifetime) return true;
    if (!row.expiry) return false;
    return Date.now() < row.expiry;
};

const sewaTimeLeft = (expiry) => {
    if (!expiry) return 'Lifetime';
    const diff = expiry - Date.now();
    if (diff <= 0) return '⏰ EXPIRED';
    const d = Math.floor(diff / 86400000);
    const h = Math.floor((diff % 86400000) / 3600000);
    const m = Math.floor((diff % 3600000) / 60000);
    if (d > 0) return `${d} hari ${h} jam`;
    if (h > 0) return `${h} jam ${m} menit`;
    return `${m} menit`;
};

