const _SPAM_TRACKER = new Map();
const _SPAM_GROUP_MUTED = new Map();

function spamAdd(gid, uid) {
  const key = `${gid}:${uid}`;
  const now = Date.now();
  const WIN = 10000;
  if (!_SPAM_TRACKER.has(key)) _SPAM_TRACKER.set(key, { timestamps: [], warnedAt: new Set() });
  const e = _SPAM_TRACKER.get(key);
  e.timestamps = e.timestamps.filter(t => now - t < WIN);
  e.timestamps.push(now);
  return e.timestamps.length;
}
function spamReset(gid, uid) {
  const key = `${gid}:${uid}`;
  if (_SPAM_TRACKER.has(key)) { _SPAM_TRACKER.get(key).timestamps = []; _SPAM_TRACKER.get(key).warnedAt = new Set(); }
}
function spamResetGroup(gid) {
  for (const k of _SPAM_TRACKER.keys()) { if (k.startsWith(gid + ':')) _SPAM_TRACKER.delete(k); }
}
function spamGetWarnedAt(gid, uid) { return _SPAM_TRACKER.get(`${gid}:${uid}`)?.warnedAt || new Set(); }

const _RAID_TRACKER = new Map();
function raidTrack(gid, count = 1) {
    if (!_RAID_TRACKER.has(gid)) _RAID_TRACKER.set(gid, []);
    const now = Date.now();
    const arr  = _RAID_TRACKER.get(gid);
    arr.push(...Array(count).fill(now));
    _RAID_TRACKER.set(gid, arr);
}
function raidCheck(gid, windowSec, maxJoin) {
    if (!_RAID_TRACKER.has(gid)) return false;
    const now    = Date.now();
    const window = windowSec * 1000;
    const recent = _RAID_TRACKER.get(gid).filter(t => now - t < window);
    _RAID_TRACKER.set(gid, recent);
    return recent.length >= maxJoin;
}
function raidReset(gid) { _RAID_TRACKER.set(gid, []); }
function spamMarkWarned(gid, uid, thr) {
  const key = `${gid}:${uid}`;
  if (!_SPAM_TRACKER.has(key)) _SPAM_TRACKER.set(key, { timestamps: [], warnedAt: new Set() });
  _SPAM_TRACKER.get(key).warnedAt.add(thr);
}

const _SLOW_TRACKER = new Map();

function slowCheck(gid, uid, delayMs) {
  const key = `${gid}:${uid}`;
  const now = Date.now();
  const last = _SLOW_TRACKER.get(key) || 0;
  if (now - last < delayMs) return false;
  _SLOW_TRACKER.set(key, now);
  return true;
}

