function isWLDomain(txt, wl) {
    if (!wl || !wl.length) return false;
    const lower = txt.toLowerCase();
    const _cleaned = lower.replace(/[\u200b\u200c\u200d\u200e\u200f\u202a-\u202e\u2060-\u2064\ufeff\u00ad\u180e\u034f\u061c]/g, '');
    return wl.some(d => lower.includes(d.toLowerCase()) || _cleaned.includes(d.toLowerCase()));
}

const _normalizeLeet = (txt) => txt
    .replace(/4/g,'a').replace(/3/g,'e').replace(/1/g,'i').replace(/0/g,'o')
    .replace(/5/g,'s').replace(/7/g,'t').replace(/8/g,'b').replace(/\$/g,'s')
    .replace(/\@/g,'a').replace(/!/g,'i').replace(/\+/g,'t')
    .replace(/[\s\.\-_\*]/g,'');

function hasToxic(txt) {
    if (!txt) return false;
    const lower   = txt.toLowerCase();
    const normed  = _normalizeLeet(lower);

    if (TOXIC_WORDS.some(w => lower.includes(w) || normed.includes(_normalizeLeet(w)))) return true;

    if (_badWordsReady && _badWordsFilter) {
        try { if (_badWordsFilter.isProfane(lower)) return true; } catch {}
    }

    if (_francReady && _francDetect) {
        try {
            const lang = _francDetect(lower, { minLength: 5 });
            if (lang === 'eng' || lang === 'und') {
                if (_badWordsReady && _badWordsFilter) {
                    try { if (_badWordsFilter.isProfane(normed)) return true; } catch {}
                }
            }
        } catch {}
    }

    return false;
}

