function gsFormatMsg(template, data) {
  return (template || "")
    .replace(/@user/g, `@${data.userId}`)
    .replace(/@subject/g, data.subject || "Grup")
    .replace(/@desc/g, data.desc || "")
    .replace(/@date/g, data.date || new Date().toLocaleDateString("id-ID"))
    .replace(/@bio/g, data.bio || "Tidak ada bio")
    .replace(/@total/g, String(data.total || "?"));
}

const handleAntiRaid = async (bulter, groupId, joinCount = 1) => {
    try {
        const _gs = gsGet(groupId);
        if (!_gs.antiraid) return;
        raidTrack(groupId, joinCount);
        const isRaid = raidCheck(groupId, _gs.antiraidWindow || 10, _gs.antiraidMax || 5);
        if (!isRaid) return;
        raidReset(groupId);

        try { await bulter.groupSettingUpdate(groupId, 'announcement'); } catch {}

        const _meta = await bulter.groupMetadata(groupId).catch(() => null);
        if (!_meta) return;
        await bulter.sendMessage(groupId, {
            text: `🚨 *RAID TERDETEKSI!*

⚠️ Ada ${_gs.antiraidMax||5}+ orang bergabung dalam ${_gs.antiraidWindow||10} detik.
🔒 Grup dikunci sementara oleh sistem anti-raid.

_Hubungi admin untuk membuka kunci._`
        });
    } catch(e) { console.error('[AntiRaid]', e.message); }
};

// Helper: Upload gambar ke tmpfiles.org → return public URL
async function _aiUploadToTmp(buffer, filename = 'image.jpg') {
    const FD = require('form-data');
    const form = new FD();
    form.append('file', buffer, { filename, contentType: 'image/jpeg' });
    try {
        const { data } = await axios.post('https://tmpfiles.org/api/v1/upload', form, {
            headers: form.getHeaders(), timeout: 60000
        });
        if (data?.status === 'success' && data?.data?.url) {
            return data.data.url.replace('tmpfiles.org/', 'tmpfiles.org/dl/');
        }
        throw new Error('tmpfiles gagal');
    } catch {
        // fallback ke Telegraph jika tmpfiles gagal
        const url = await TelegraPh(buffer);
        return url;
    }
}

// Helper: FAA Transform — upload gambar lalu proses dengan api-faa.my.id
async function _faaTransform(buffer, endpoint) {
    const imageUrl = await _aiUploadToTmp(buffer);
    const { data } = await axios.get(
        `https://api-faa.my.id/faa/${endpoint}?url=${encodeURIComponent(imageUrl)}`,
        { responseType: 'arraybuffer', timeout: 120000 }
    );
    return Buffer.from(data);
}

// Helper: NanoBanana AI — Edit gambar via prompt
async function _nanoBanana(imageBuffer, prompt) {
    const imageUrl = await _aiUploadToTmp(imageBuffer, `nano_${Date.now()}.jpg`);
    const apiUrl = `https://api-faa.my.id/faa/nano-banana?url=${encodeURIComponent(imageUrl)}&prompt=${encodeURIComponent(prompt)}`;
    const { data } = await axios.get(apiUrl, { responseType: 'arraybuffer', timeout: 120000 });
    return Buffer.from(data);
}

