const _CHATGOT_DB_PATH = './database/chatgot.json';
const _CHATGOT_MODELS  = {
    claude:    'anthropic/claude-3-haiku',
    gpt41mini: 'openai/gpt-4.1-mini',
    gpt4omini: 'openai/gpt-4o-mini',
    gemini:    'google/gemini-2.5-flash-lite',
    deepseek:  'deepseek/deepseek-chat'
};

function _chatgotReadAcc() {
    try { return JSON.parse(fs.readFileSync(_CHATGOT_DB_PATH, 'utf8')); } catch { return null; }
}
function _chatgotSaveAcc(data) {
    try { fs.writeFileSync(_CHATGOT_DB_PATH, JSON.stringify(data, null, 2)); } catch {}
}

async function _chatgotRegister() {
    const _sleep = (ms) => new Promise(r => setTimeout(r, ms));
    const crypto = require('crypto');

    // 1. Buat email temporer
    const { data: mailData } = await axios.get('https://api.yabes-desu.workers.dev/test/mail', {
        params: { action: 'create' }, timeout: 15000
    });
    const email = mailData.email;

    // 2. Bypass Cloudflare Turnstile
    const { data: cfData } = await axios.get('https://api.gimita.id/api/tools/bypasscf', {
        params: {
            method: 'turnstile-min',
            siteKey: '0x4AAAAAAAxfq-hBQkOyW7zF',
            url: 'https://www.chatgot.io/chat/'
        }, timeout: 20000
    });

    // 3. Kirim email verifikasi
    await axios.post('https://api.chatgot.io/api/verify/send-email', {
        email, type: 'register', cf_challenge_token: cfData.data
    }, {
        headers: { 'content-type': 'application/json', 'i-version': '1.1.70', 'i-lang': 'en', 'i-platform': 'web_h5' }
    });

    // 4. Tunggu & ambil kode OTP
    let code = null;
    for (let i = 0; i < 30 && !code; i++) {
        await _sleep(2000);
        try {
            const { data: msgData } = await axios.get('https://api.yabes-desu.workers.dev/test/mail', {
                params: { action: 'message', email }, timeout: 10000
            });
            const list = Array.isArray(msgData?.data) ? msgData.data : (msgData?.data ? [msgData.data] : []);
            for (const msg of list) {
                const content = msg.text_content || msg.html_content || '';
                const match = content.match(/\b\d{6}\b/);
                if (match) { code = match[0]; break; }
            }
        } catch {}
    }
    if (!code) throw new Error('Gagal mendapatkan kode OTP dari email');

    // 5. Register akun
    const password = crypto.createHash('md5').update(crypto.randomUUID()).digest('hex');
    await axios.post('https://api.chatgot.io/api/user/register', {
        email, password, emailCode: code, invitationId: '',
        gtag: { utm_source: 'chatgot_www', utm_medium: 'unknow', utm_campaign: 'unknow', utm_term: 'unknow', utm_content: 'unknow', utm_id: 'unknow' }
    }, {
        headers: { 'content-type': 'application/json', 'i-version': '1.1.70', 'i-lang': 'en', 'i-platform': 'web_h5' }
    });

    const account = { email, password, created_at: Date.now() };
    _chatgotSaveAcc(account);
    return account;
}

async function _chatgotAI(prompt, modelKey = 'gpt4omini') {
    let account = _chatgotReadAcc();
    if (!account) account = await _chatgotRegister();

    // Login & ambil token
    let token;
    try {
        const { data: loginData } = await axios.post('https://api.chatgot.io/api/user/login',
            { email: account.email, password: account.password },
            { headers: { 'content-type': 'application/json', 'i-version': '1.1.70', 'i-lang': 'en', 'i-platform': 'web_h5' } }
        );
        token = loginData.data.token;
    } catch (e) {
        // Akun mungkin expired, register ulang
        account = await _chatgotRegister();
        const { data: loginData } = await axios.post('https://api.chatgot.io/api/user/login',
            { email: account.email, password: account.password },
            { headers: { 'content-type': 'application/json', 'i-version': '1.1.70', 'i-lang': 'en', 'i-platform': 'web_h5' } }
        );
        token = loginData.data.token;
    }

    const model = _CHATGOT_MODELS[modelKey] || _CHATGOT_MODELS.gpt4omini;

    const res = await axios.post('https://api.chatgot.io/api/v2/chat/conversation', {
        model, prompt, webAccess: 'close', timezone: 'Asia/Jakarta'
    }, {
        headers: {
            'content-type': 'application/json',
            authorization: `Bearer ${token}`,
            'i-version': '1.1.70', 'i-lang': 'en', 'i-platform': 'web_h5'
        },
        responseType: 'stream', timeout: 90000
    });

    return new Promise((resolve, reject) => {
        let fullText = '';
        res.data.on('data', chunk => {
            for (const line of chunk.toString().split('\n')) {
                if (!line.startsWith('data:')) continue;
                const json = line.slice(5).trim();
                if (!json) continue;
                try {
                    const parsed = JSON.parse(json);
                    if (parsed?.data?.content) fullText += parsed.data.content;
                } catch {}
            }
        });
        res.data.on('end', () => resolve(fullText.trim() || 'AI tidak merespons'));
        res.data.on('error', reject);
    });
}

// Helper: Dolphin AI (POST streaming)
async function _dolphinAI(question, template = 'logical') {
    const { data } = await axios.post('https://chat.dphn.ai/api/chat', {
        messages: [{ role: 'user', content: question }],
        model: 'dolphinserver:24B',
        template
    }, {
        headers: {
            origin: 'https://chat.dphn.ai',
            referer: 'https://chat.dphn.ai/',
            'user-agent': 'Mozilla/5.0 (Linux; Android 15; SM-F958) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/130.0.6723.86 Mobile Safari/537.36'
        }, timeout: 120000
    });
    const result = data.split('\n\n')
        .filter(line => line && line.startsWith('data: {'))
        .map(line => { try { return JSON.parse(line.substring(6)); } catch { return null; } })
        .filter(Boolean)
        .map(line => line?.choices?.[0]?.delta?.content || '')
        .join('');
    if (!result) throw new Error('Tidak ada respons dari Dolphin AI');
    return result;
}


