function _findSuggestions(cmdTyped) {
    if (!cmdTyped || cmdTyped.length < 1) return [];
    const lower = cmdTyped.toLowerCase().trim();
    if (_ALL_CMDS.includes(lower)) return [];
    const scored = _ALL_CMDS.map(c => ({
        c,
        d: _levenshtein(c, lower),
        starts: c.startsWith(lower.slice(0, Math.max(2, lower.length - 1)))
    }));
    const results = scored
        .filter(x => x.d <= Math.min(2, Math.floor(lower.length / 2) + 1) || x.starts)
        .sort((a, b) => a.d - b.d || (b.starts ? 1 : 0) - (a.starts ? 1 : 0))
        .slice(0, 3)
        .map(x => x.c);
    return [...new Set(results)];
}

