                const _aiHr    = parseInt(_aiNowD.toLocaleTimeString('id-ID',{hour:'2-digit',hour12:false,timeZone:'Asia/Jakarta'})) || 12;
                const _aiWkt   = _aiHr>=4&&_aiHr<11?'pagi':_aiHr>=11&&_aiHr<15?'siang':_aiHr>=15&&_aiHr<18?'sore':'malam';
                const _aiHari  = _aiNowD.toLocaleDateString('id-ID',{weekday:'long',timeZone:'Asia/Jakarta'});

                // Session per-user
