                const _aiOwnerSend = _aiIsOwner(m.sender);

                // Reset sesi jika idle melebihi TTL
                if ((Date.now() - (_aiSess.lastReset||0)) > _AI_SESSION_TTL && _aiSess.history.length > 0) {
                    _aiSess.history   = [];
                    _aiSess.lastReset = Date.now();
                    _aiSess.msgCount  = 0;
                }
                _aiSess.msgCount = (_aiSess.msgCount || 0) + 1;

                // Bersihkan input dari tag bot
                let _aiInput = String(body||'').trim()
                    .replace(new RegExp('@?' + _aiBotNum, 'g'), '')
                    .replace(/\s{2,}/g,' ').trim();
