        if (global[_skK]) {
            if (/^(nyerah|skip|menyerah)$/.test(_gaB)){const a=global[_skK].jawab;delete global[_skK];await bulter.sendMessage(m.chat,{text:`🏳️ @${m.sender.split('@')[0]} menyerah!\n\n✅ Kata: *${a}*`,mentions:[m.sender]}).catch(()=>{});}
            else if (_gaB===global[_skK]?.jawab?.toLowerCase()){const a=global[_skK].jawab;delete global[_skK];await bulter.sendMessage(m.chat,{text:`🎉 *BENAR!*\n\n👤 @${m.sender.split('@')[0]} berhasil!\n✅ Kata: *${a}*`,mentions:[m.sender]}).catch(()=>{});}
        }
