                        if (!_stTie)_stW=((_stR.p1c==='batu'&&_stR.p2c==='gunting')||(_stR.p1c==='gunting'&&_stR.p2c==='kertas')||(_stR.p1c==='kertas'&&_stR.p2c==='batu'))?_stR.p:_stR.p2;
                        let r=`✊✌️✋ *ʜᴀsɪʟ sᴜɪᴛ*\n\n@${_stR.p.split('@')[0]} ${_stE[_stR.p1c]} ${_stR.p1c}\n@${_stR.p2.split('@')[0]} ${_stE[_stR.p2c]} ${_stR.p2c}\n\n`;
                        r+=_stTie?`🤝 *SERI!*`:`🏆 *@${_stW.split('@')[0]} MENANG!*`;
