function rpgSyncClassStats(user) {
    if (!user.class || !RPG_CLASSES[user.class]) return;

    var cls = RPG_CLASSES[user.class];
    var lvl = user.level || 1;

    user.maxHp = cls.baseHp + Math.floor((cls.growHp || 0) * (lvl - 1));
    user.maxMana = cls.baseMana + Math.floor((cls.growMana || 0) * (lvl - 1));
    user.attack = cls.baseAtk + Math.floor((cls.growAtk || 0) * (lvl - 1));
    user.defense = cls.baseDef + Math.floor((cls.growDef || 0) * (lvl - 1));
    user.speed = cls.baseSpd + Math.floor((cls.growSpd || 0) * (lvl - 1));
    user.magicAttack = cls.baseMagAtk || 5;
    user.magicDefense = cls.baseMagDef || 3;
    user.critRate = cls.baseCrit || 5;
    user.dodgeRate = cls.baseDodge || 3;

    if (user.hp > user.maxHp) user.hp = user.maxHp;
    if (user.mana > user.maxMana) user.mana = user.maxMana;
}

function rpgInitEco(db, jid) {
    if (!db[jid]) {
        db[jid] = {
            wallet: 0,
            bank: 0,
            bankMax: 500000,
            bankInterest: 0.5,
            lastInterest: Date.now(),
            totalEarned: 0,
            totalSpent: 0,
            totalTransferred: 0,
            dailyClaimed: false,
            lastDailyReset: 0,
            dailyStreak: 0,
            longestDailyStreak: 0,
            weeklyClaimed: false,
            lastWeeklyReset: 0
        };
    }
    return db[jid];
}


