    await bulter.sendMessage(m.chat, {
        text:
            `🗑️ *PROFIL DIHAPUS*\\n\\n` +
            `┃ • User: @${_udTarget.split('@')[0]}\\n` +
            `┃ • Akun registrasi dihapus`,
        mentions: [_udTarget],
    }, { quoted: fakeQuoted });
