    bulter.sendMessage(m.chat, { react: { text: '⏳', key: m.key } });

    try {
        // Tentukan target: reply > mention > diri sendiri
        let targetJid = m.sender;
        let targetName = m.pushName || m.msg?.pushName || '';

        // Jika reply pesan orang lain
        if (m.quoted && m.quoted.sender) {
            targetJid = m.quoted.sender;
            targetName = '';
        }
        // Jika mention user
        if (m.mentionedJid && m.mentionedJid.length > 0) {
            targetJid = m.mentionedJid[0];
            targetName = '';
        }

        // Coba ambil nama dari contact / participants
        if (!targetName || targetName === '') {
            try {
                if (m.isGroup) {
                    const groupMeta = groupMetadata || await bulter.groupMetadata(m.chat).catch(() => null);
                    if (groupMeta?.participants) {
                        const found = groupMeta.participants.find(p => (p.id || p.jid) === targetJid);
                        if (found?.notify) targetName = found.notify;
                    }
                }
            } catch {}
        }

        // Fallback nama
        if (!targetName || targetName === '') {
            targetName = '+' + targetJid.split('@')[0];
        }

        // Ambil profile picture
        let ppUrl = global.thumnail2 || '';
        try { ppUrl = await bulter.profilePictureUrl(targetJid, 'image'); } catch {}

        // Ambil bio/status
        let bio = '';
        try {
            const statusResult = await bulter.fetchStatus(targetJid).catch(() => null);
            if (statusResult?.status) bio = statusResult.status;
        } catch {}

        // Ambil data dari grupstats database
        const _ucDb = loadStats();
        let totalChat = 0;
        let groupCount = 0;
        let rankInCurrentGroup = 0;
        let joinDate = '-';
        let lastSeenStr = '-';

        // Hitung total chat di semua grup
        const allGroupIds = Object.keys(_ucDb);
        allGroupIds.forEach(gid => {
            const gData = _ucDb[gid];
            if (gData?.members?.[targetJid]) {
                totalChat += gData.members[targetJid];
                groupCount++;
            }
        });

        // Hitung rank di grup saat ini
        if (m.isGroup && _ucDb[m.chat]?.members) {
            const sorted = Object.entries(_ucDb[m.chat].members)
                .sort((a, b) => b[1] - a[1]);
            const idx = sorted.findIndex(([jid]) => jid === targetJid);
            rankInCurrentGroup = idx >= 0 ? idx + 1 : 0;
        }

        // Last seen dari DB
        if (m.isGroup && _ucDb[m.chat]?.lastSeen?.[targetJid]) {
            try {
                const lsTimestamp = _ucDb[m.chat].lastSeen[targetJid];
                const lsDate = new Date(lsTimestamp);
                lastSeenStr = lsDate.toLocaleString('id-ID', {
                    timeZone: 'Asia/Jakarta',
                    day: '2-digit', month: 'short', year: 'numeric',
                    hour: '2-digit', minute: '2-digit'
                }) + ' WIB';
            } catch {}
        }

        // Cek nama tersimpan di DB
        for (const gid of allGroupIds) {
            const gData = _ucDb[gid];
            if (gData?.names?.[targetJid] && gData.names[targetJid] !== 'No Name') {
                if (!targetName || targetName.startsWith('+')) {
                    targetName = gData.names[targetJid];
                }
                break;
            }
        }

        // ── Level & XP ──
        const xpPerLevel = 50;
        const level = Math.floor(totalChat / xpPerLevel) + 1;
        const xp = totalChat % xpPerLevel;
        const xpMax = xpPerLevel;

        // ── Role ──
        let role = 'Member';
        if (m.isGroup) {
            try {
                const groupMeta = groupMetadata || await bulter.groupMetadata(m.chat).catch(() => null);
                if (groupMeta?.participants) {
                    const participantData = groupMeta.participants.find(p => (p.id || p.jid) === targetJid);
                    if (participantData) {
                        if (participantData.admin === 'superadmin') role = 'Owner';
                        else if (participantData.admin === 'admin') role = 'Admin';
                    }
                }
            } catch {}
        }
        // Cek owner bot
        try {
            const ownerNumber = ((global.owner || [])[0] || '').replace(/[^0-9]/g,'');
            if (targetJid === ownerNumber + '@s.whatsapp.net' || targetJid === bulter.user?.id?.split(':')[0] + '@s.whatsapp.net') {
                role = 'Owner Bot';
            }
        } catch {}

        // ── Premium ──
        let isPremium = false;
        try {
            if (typeof checkPremium === 'function') isPremium = checkPremium(targetJid);
            else if (global.db?.data?.users?.[targetJid]?.premium) isPremium = true;
        } catch {}

        // ── Badges ──
        const badges = [];
        try {
            if (m.isGroup && _ucDb[m.chat]?.members) {
                const sorted = Object.entries(_ucDb[m.chat].members).sort((a, b) => b[1] - a[1]);
                const ri = sorted.findIndex(([jid]) => jid === targetJid);
                if (ri >= 0 && ri < 3) badges.push('top_chatter');
            }
            if (m.isGroup && _ucDb[m.chat]?.hourly) {
                let earlyCount = 0, nightCount = 0;
                Object.values(_ucDb[m.chat].hourly).forEach(dayArr => {
                    for (let h = 5; h <= 8; h++) earlyCount += (dayArr[h] || 0);
                    for (let h = 22; h <= 23; h++) nightCount += (dayArr[h] || 0);
                    for (let h = 0; h <= 3; h++) nightCount += (dayArr[h] || 0);
                });
                if (earlyCount > 10) badges.push('early_bird');
                if (nightCount > 10) badges.push('night_owl');
            }
            if (groupCount >= 3) badges.push('loyal');
            if (totalChat > 100) badges.push('active');
            if (totalChat < 20) badges.push('newbie');
        } catch {}

        // ── Join date ──
        try {
            if (m.isGroup && _ucDb[m.chat]?.hourly) {
                const firstDay = Object.keys(_ucDb[m.chat].hourly).sort()[0];
                if (firstDay) {
                    joinDate = new Date(firstDay).toLocaleDateString('id-ID', {
                        timeZone: 'Asia/Jakarta',
                        day: '2-digit', month: 'short', year: 'numeric'
                    });
                }
            }
        } catch {}

        // ── Generate gambar ──
        const { loadImage } = require('canvas');
        const cardBuffer = await generateUserCard({
            name: targetName,
            jid: targetJid,
            ppUrl: ppUrl,
            bio: bio,
            level: level,
            xp: xp,
            xpMax: xpMax,
            rank: rankInCurrentGroup,
            totalChat: totalChat,
            groupCount: groupCount,
            isPremium: isPremium,
            role: role,
            joinDate: joinDate,
            lastSeen: lastSeenStr,
            badge: badges,
        }, loadImage);

        // ── Caption ──
        const phone = '+' + targetJid.split('@')[0];
        const badgeLabels = {
            'top_chatter': 'Top Chatter',
            'early_bird': 'Early Bird',
            'night_owl': 'Night Owl',
            'loyal': 'Loyal Member',
            'active': 'Active User',
            'newbie': 'Newbie',
        };
        const badgeText = badges.length > 0
            ? badges.map(b => badgeLabels[b] || b).join(', ')
            : 'Belum ada';

        const captionText =
            `╭─ \`USER CARD\` 𝜗ৎ\n` +
            `┆ ᵎᵎ Nama     : *${targetName}*\n` +
            `┆ ᵎᵎ Nomor    : ${phone}\n` +
            `┆ ᵎᵎ Role     : *${role}*\n` +
            (isPremium ? `┆ ᵎᵎ Status   : *Premium User ✦*\n` : '') +
            (bio ? `┆ ᵎᵎ Bio      : _${bio.slice(0, 50)}_\n` : '') +
            `╰─────\n\n` +
            `╭─ \`STATISTIK\` 𝜗ৎ\n` +
            `┆ ᵎᵎ Level    : *${level}*\n` +
            `┆ ᵎᵎ XP       : *${xp}/${xpMax}* (${(xp / xpMax * 100).toFixed(1)}%)\n` +
            (rankInCurrentGroup > 0 ? `┆ ᵎᵎ Rank     : *#${rankInCurrentGroup}* di grup ini\n` : '') +
            `┆ ᵎᵎ Chat     : *${totalChat.toLocaleString('id-ID')}* pesan\n` +
            `┆ ᵎᵎ Grup     : *${groupCount}* grup aktif\n` +
            `┆ ᵎᵎ Badge    : ${badgeText}\n` +
            `╰─────\n\n` +
            `╭─ \`AKTIVITAS\` 𝜗ৎ\n` +
            `┆ ᵎᵎ Gabung   : *${joinDate}*\n` +
            `┆ ᵎᵎ Aktif    : *${lastSeenStr}*\n` +
            `╰───── ${global.namaBot || 'Bot'}`;

        await bulter.sendMessage(m.chat, {
            image: cardBuffer,
            caption: captionText,
        }, { quoted: m });

        bulter.sendMessage(m.chat, { react: { text: '✅', key: m.key } });

    } catch (e) {
        _L.error('UserCard', String(e.message||e));
        bulter.sendMessage(m.chat, { react: { text: '❌', key: m.key } });
        reply(`❌ Gagal membuat usercard: ${e.message}`);
    }
    break;
