                if (_cf_diffDetails.length > 8) _cf_diffCaption += `┃ _...dan ${_cf_diffDetails.length - 8} perubahan lainnya_\n`;
                _cf_diffCaption += `╰┈┈┈┈┈┈┈┈⬡`;
