            const dst=await bulter.groupMetadata(m.chat), djids=(dst.participants||[]).map(p=>p.id||p.jid);
            const botJ=bulter.user?.id?.split(':')[0]+'@s.whatsapp.net';
            const bl=global._CM_BLACKLIST[m.chat]||[], wl=global._CM_WHITELIST[m.chat]||[];
