            const toAdd=(_srcMeta.participants||[]).map(p=>p.id||p.jid).filter(j=>j&&j!==botJ&&j!==m.sender&&!djids.includes(j)&&!bl.includes(j)).filter(j=>!wl.length||wl.includes(j)).slice(0,lim);
            if (!toAdd.length) return reply('⚠️ Tidak ada member baru.');
