    const _limitOpt=parseInt(_cm.match(/limit:(\d+)/i)?.[1]||'999');
    const _delayOpt=parseInt(_cm.match(/delay:(\d+)/i)?.[1]||'3')*1000;
    const _adminOnly=/adminonly/i.test(_cm);
    const _regionOpt=_cm.match(/region:([A-Z,]+)/i)?.[1]?.split(',')||[];
    const _skipList=(_cm.match(/skip:([\d,]+)/i)?.[1]||'').split(',').filter(Boolean).map(n=>n.trim()+'@s.whatsapp.net');
