async function talkaiScrape(message) {
    if (!message) throw new Error('Message is required')
    const ua = pickUA()
    let token = null
    let cookies = ''
    const pages = ['https://talkai.info/', 'https://talkai.info/chat/', 'https://talkai.info/id/', 'https://talkai.info/id/chat/']
    for (const page of pages) {
        try {
            const res = await axios.get(page, {
                headers: {
                    'User-Agent': ua,
                    'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,image/webp,*/*;q=0.8',
                    'Accept-Language': 'id-ID,id;q=0.9,en-US;q=0.8',
                    'Cache-Control': 'no-cache'
                },
                timeout: 15000,
                maxRedirects: 5
            })
            const sc = res.headers['set-cookie']
            if (sc) cookies = sc.map(c => c.split(';')[0]).join('; ')
            const html = res.data
            const $ = cheerio.load(html)
            token = $('meta[name="csrf-token"]').attr('content') ||
                    $('meta[name="token"]').attr('content') ||
                    $('input[name="_token"]').val() ||
                    $('input[name="token"]').val() ||
                    $('input[name="csrf_token"]').val()
            if (!token) {
                const regexes = [
                    /csrf[_-]?token["']?\s*[:=]\s*["']([^"']+)["']/i,
                    /"token"\s*:\s*"([^"]+)"/,
                    /var\s+token\s*=\s*['"]([^'"]+)['"]/,
                    /"csrfToken"\s*:\s*"([^"]+)"/,
                    /name="_token"\s+value=["']([^"']+)["']/,
                    /data-token=["']([^"']+)["']/
                ]
                for (const regex of regexes) {
                    const match = html.match(regex)
                    if (match && match[1]) { token = match[1]; break }
                }
            }
            if (token) break
        } catch (e) { continue }
    }

    let result = null
    let lastError = null

    const attempts = [
        {
            url: 'https://talkai.info/chat/send/',
            data: JSON.stringify({ message: message, model: 'gpt-4o-mini', stream: false }),
            ct: 'application/json'
        },
        {
            url: 'https://talkai.info/api/chat/',
            data: JSON.stringify({ messages: [{ role: 'user', content: message }], model: 'gpt-4o-mini' }),
            ct: 'application/json'
        },
        {
            url: 'https://talkai.info/chat/send/',
            data: (() => { const f = new URLSearchParams(); f.append('message', message); f.append('model', 'gpt-4o-mini'); if (token) f.append('_token', token); return f.toString() })(),
            ct: 'application/x-www-form-urlencoded'
        },
        {
            url: 'https://talkai.info/id/chat/send/',
            data: JSON.stringify({ message: message, model: 'gpt-4o-mini', stream: false }),
            ct: 'application/json'
        }
    ]

    for (const attempt of attempts) {
        try {
            const headers = {
                'Content-Type': attempt.ct,
                'User-Agent': ua,
                'Accept': 'application/json, text/plain, */*',
                'Origin': 'https://talkai.info',
                'Referer': 'https://talkai.info/chat/',
                'X-Requested-With': 'XMLHttpRequest',
                'Cookie': cookies,
                'Accept-Language': 'id-ID,id;q=0.9'
            }
            if (token) {
                headers['X-CSRF-TOKEN'] = token
                headers['X-Token'] = token
            }
            const res = await axios.post(attempt.url, attempt.data, { headers, timeout: 30000 })
            const extracted = extractResponse(res.data)
            if (extracted) { result = extracted; break }
        } catch (e) { lastError = e }
    }

    if (!result) throw new Error(lastError?.message || 'Tidak ada respons dari TalkAI')
    return result
}

